import boto3
import os
import logging
from urllib.parse import unquote_plus

# Configure logging
logger = logging.getLogger()
logger.setLevel(logging.INFO)

s3_client = boto3.client('s3')
sns_client = boto3.client('sns')

# Environment variables (configure in Lambda console)
# OUTPUT_BUCKET_NAME = "your-output-bucket"
# SNS_TOPIC_ARN = "arn:aws:sns:your-region:your-account-id:your-sns-topic-name"

def lambda_handler(event, context):
    """
    AWS Lambda function to process user-uploaded images from S3.
    Reads from S3, simulates processing, writes results back to S3,
    sends SNS notifications, and logs to CloudWatch.
    """
    
    # Get environment variables
    output_bucket_name = os.environ.get('OUTPUT_BUCKET_NAME')
    sns_topic_arn = os.environ.get('SNS_TOPIC_ARN')

    if not output_bucket_name:
        logger.error("OUTPUT_BUCKET_NAME environment variable not set.")
        return {
            'statusCode': 500,
            'body': 'Configuration error: OUTPUT_BUCKET_NAME not set.'
        }
    if not sns_topic_arn:
        logger.error("SNS_TOPIC_ARN environment variable not set.")
        return {
            'statusCode': 500,
            'body': 'Configuration error: SNS_TOPIC_ARN not set.'
        }

    for record in event['Records']:
        bucket_name = record['s3']['bucket']['name']
        key = unquote_plus(record['s3']['object']['key'])
        
        logger.info(f"Processing object: {key} from bucket: {bucket_name}")

        try:
            # 1. Read from S3
            response = s3_client.get_object(Bucket=bucket_name, Key=key)
            image_content = response['Body'].read()
            content_type = response['ContentType']
            logger.info(f"Successfully read object {key}. Size: {len(image_content)} bytes. Content-Type: {content_type}")

            # Simulate image processing (e.g., resizing, watermarking, metadata extraction)
            processed_data = f"Processed content for {key}: Original size {len(image_content)} bytes. Mock processing complete."
            processed_key = f"processed/{os.path.basename(key).split('.')[0]}.txt" # Example output key
            
            logger.info(f"Simulating processing for {key}. Result will be written to {output_bucket_name}/{processed_key}")

            # 2. Write results back to S3
            s3_client.put_object(
                Bucket=output_bucket_name,
                Key=processed_key,
                Body=processed_data.encode('utf-8'),
                ContentType='text/plain'
            )
            logger.info(f"Successfully wrote processed data to s3://{output_bucket_name}/{processed_key}")

            # 3. Send notifications via SNS
            sns_message = {
                'default': f"Image '{key}' from bucket '{bucket_name}' processed successfully. "
                           f"Result saved to s3://{output_bucket_name}/{processed_key}.",
                's3_event': record
            }
            
            sns_client.publish(
                TopicArn=sns_topic_arn,
                Message=sns_message['default'],
                MessageAttributes={
                    'EventType': {
                        'DataType': 'String',
                        'StringValue': 'ImageProcessed'
                    },
                    'OriginalKey': {
                        'DataType': 'String',
                        'StringValue': key
                    },
                    'ProcessedKey': {
                        'DataType': 'String',
                        'StringValue': processed_key
                    },
                    'OriginalBucket': {
                        'DataType': 'String',
                        'StringValue': bucket_name
                    }
                }
            )
            logger.info(f"Notification sent to SNS topic: {sns_topic_arn} for image: {key}")

        except Exception as e:
            logger.error(f"Error processing object {key} from bucket {bucket_name}: {e}")
            # Optionally send an error notification
            sns_client.publish(
                TopicArn=sns_topic_arn,
                Message=f"ERROR processing image '{key}' from bucket '{bucket_name}': {e}",
                MessageAttributes={
                    'EventType': {
                        'DataType': 'String',
                        'StringValue': 'ImageProcessingError'
                    },
                    'OriginalKey': {
                        'DataType': 'String',
                        'StringValue': key
                    },
                    'OriginalBucket': {
                        'DataType': 'String',
                        'StringValue': bucket_name
                    }
                }
            )
            # Depending on requirements, you might want to re-raise the exception or mark the record as failed.
            # For this MVP, we log and continue.

    return {
        'statusCode': 200,
        'body': 'Image processing initiated for all records.'
    }